// tsconfig.json üçün qeyd: {"experimentalDecorators": true}

// 1. Sadə Class Dekoratoru
function sealed(constructor: Function) {
  Object.seal(constructor);
  Object.seal(constructor.prototype);
}
@sealed
class User {
  name: string = "Alice";
  greet(): string {
    return "Hello, " + this.name;
  }
}
const user = new User();
console.log(user.greet()); // Çıxış: Hello, Alice

// 2. Dekorator Fabriki
function logClass(prefix: string) {
  return function (constructor: Function) {
    console.log(prefix + " class created: " + constructor.name);
  };
}
@logClass("Info")
class Product {
  name: string = "Laptop";
  price: number = 999;
}
// Çıxış: Info class created: Product

// 3. Sinifə Xüsusiyyət Əlavə Edən Dekorator
function addTimestamp(constructor: Function) {
  constructor.prototype.createdAt = new Date().toISOString();
}
@addTimestamp
class Order {
  id: string = "O001";
}
const order = new Order();
console.log((order as any).createdAt); // Çıxış: 2025-07-09T...

// 4. Digər Dekoratorlarla Birləşmə
function logMethod(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    console.log("Method " + propertyKey + " called with args: " + args);
    return originalMethod.apply(this, args);
  };
}
@logClass("Store")
class Store {
  @logMethod
  addItem(item: string): string {
    return "Added " + item;
  }
}
const store = new Store();
console.log(store.addItem("Book")); // Çıxış: Store class created: Store
// Çıxış: Method addItem called with args: Book
// Çıxış: Added Book

// Mağaza sistemi
function logCreation(constructor: Function) {
  console.log("New " + constructor.name + " created at " + new Date().toISOString());
}
interface Product {
  id: string;
  name: string;
  price: number;
}
@logCreation
class Store {
  products: Product[] = [];
  addProduct(product: Product): Product[] {
    this.products = [...this.products, product];
    return this.products;
  }
}
const store = new Store();
const laptop: Product = { id: "P001", name: "Laptop", price: 999 };
store.addProduct(laptop);
// Çıxış: New Store created at 2025-07-09T...
console.log(store.products); // Çıxış: [{ id: "P001", name: "Laptop", price: 999 }]

